public class ClusteredCacheFactory implements CacheFactoryStrategy {

    private static final SystemProperty<String> HAZELCAST_EXECUTOR_SERVICE_NAME = SystemProperty.Builder.ofType(String.class).setKey("hazelcast.executor.service.name").setDefaultValue("openfire::cluster::executor").setDynamic(false).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<Duration> MAX_CLUSTER_EXECUTION_TIME = SystemProperty.Builder.ofType(Duration.class).setKey("hazelcast.max.execution.seconds").setDefaultValue(Duration.ofSeconds(30)).setChronoUnit(ChronoUnit.SECONDS).setDynamic(true).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<Duration> CLUSTER_STARTUP_RETRY_TIME = SystemProperty.Builder.ofType(Duration.class).setKey("hazelcast.startup.retry.seconds").setDefaultValue(Duration.ofSeconds(10)).setChronoUnit(ChronoUnit.SECONDS).setDynamic(true).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<Integer> CLUSTER_STARTUP_RETRY_COUNT = SystemProperty.Builder.ofType(Integer.class).setKey("hazelcast.startup.retry.count").setDefaultValue(1).setDynamic(true).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<String> HAZELCAST_CONFIG_FILE = SystemProperty.Builder.ofType(String.class).setKey("hazelcast.config.xml.filename").setDefaultValue("hazelcast-cache-config.xml").setDynamic(false).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<Boolean> HAZELCAST_JMX_ENABLED = SystemProperty.Builder.ofType(Boolean.class).setKey("hazelcast.config.jmx.enabled").setDefaultValue(Boolean.FALSE).setDynamic(false).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<Boolean> HAZELCAST_REST_ENABLED = SystemProperty.Builder.ofType(Boolean.class).setKey("hazelcast.config.rest.enabled").setDefaultValue(Boolean.FALSE).setDynamic(false).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final SystemProperty<Boolean> HAZELCAST_MEMCACHE_ENABLED = SystemProperty.Builder.ofType(Boolean.class).setKey("hazelcast.config.memcache.enabled").setDefaultValue(Boolean.FALSE).setDynamic(false).setPlugin(HazelcastPlugin.PLUGIN_NAME).build();

    private static final Logger logger = LoggerFactory.getLogger(ClusteredCacheFactory.class);

    public static final String PLUGIN_NAME = "hazelcast";

    /**
     * Keep serialization strategy the server was using before we set our strategy. We will
     * restore old strategy when plugin is unloaded.
     */
    private ExternalizableUtilStrategy serializationStrategy;

    /**
     * Storage for cache statistics
     */
    private static Map<String, Map<String, long[]>> cacheStats;

    private static HazelcastInstance hazelcast = null;

    private static Cluster cluster = null;

    private ClusterListener clusterListener;

    private String lifecycleListener;

    private String membershipListener;

    /**
